@app.route('/alert', methods=['GET', 'POST'])
def weatherAlert():
    alert_items = load_alerts()
    severity_levels = ['All', 'critcal', 'High', 'med', 'low']
    selected_severity = []
    selected_location_id = None

    if request.method == 'POST':
        selected_severity = request.form.getlist('selected_severity')
        selected_location_id = request.form.get('selected_location_id')

        # Filter alerts by severity and location
        if selected_severity and 'All' not in selected_severity:
            filtered_alerts = []
            for alert in alert_items:
                severity_str = 'med'
                # Map severity_level int back to string approximate for filtering
                sl = alert.get('severity_level', 0)
                if sl >= 4:
                    severity_str = 'critcal'
                elif sl == 3:
                    severity_str = 'High'
                elif sl == 2:
                    severity_str = 'med'
                elif sl == 1:
                    severity_str = 'low'
                else:
                    severity_str = 'All'
                if severity_str in selected_severity:
                    filtered_alerts.append(alert)
            alert_items = filtered_alerts

        if selected_location_id and selected_location_id != 'None':
            alert_items = [a for a in alert_items if a['location'] == selected_location_id]

    # Load location data for dropdown
    locations_data_raw = load_locations()
    locations_data = [{'locId': loc['loc_id'], 'locationName': loc['locationName']} for loc in locations_data_raw]

    return render_template('alerts.htm', alert_items=alert_items, severity_levels=severity_levels, locations_data=locations_data,
